+                "gpt-test".to_string(),
+                "openai".to_string(),
+                "openai".to_string(),
+            );
+            let mut out = Vec::new();
+
+            while let Some(item) = state.event_source.next().await {
+                let msg = match item {
+                    Ok(msg) => msg,
+                    Err(err) => panic!("SSE error: {err}"),
