+                content_index: None,
+                delta: None,
+                content: None,
+                reason: Some(reason_to_string(reason)),
+            },
+            StreamEvent::Error { reason, .. } => EventSummary {
+                kind: "error".to_string(),
+                content_index: None,
+                delta: None,
+                content: None,
+                reason: Some(reason_to_string(reason)),
+            },
+            StreamEvent::TextStart { content_index, .. } => EventSummary {
+                kind: "text_start".to_string(),
+                content_index: Some(*content_index),
+                delta: None,
+                content: None,
+                reason: None,
+            },
+            StreamEvent::TextEnd {
+                content_index,
+                content,
+                ..
+            } => EventSummary {
+                kind: "text_end".to_string(),
+                content_index: Some(*content_index),
+                delta: None,
+                content: Some(content.clone()),
+                reason: None,
+            },
+            _ => EventSummary {
+                kind: "other".to_string(),
+                content_index: None,
+                delta: None,
+                content: None,
+                reason: None,
+            },
+        }
+    }
+
+    fn reason_to_string(reason: &StopReason) -> String {
+        match reason {
+            StopReason::Stop => "stop",
+            StopReason::Length => "length",
+            StopReason::ToolUse => "tool_use",
+            StopReason::Error => "error",
+            StopReason::Aborted => "aborted",
+        }
+        .to_string()
+    }
 }

