+                recorder
+                    .record_streaming_with(request.clone(), || async {
+                        Ok(StreamingResponse::from_parts(
+                            200,
+                            vec![("content-type".to_string(), "text/event-stream".to_string())],
+                            vec![b"event: message\ndata: ok\n\n".to_vec()],
