+    ($logger:expr, $level:ident, $category:expr, $message:expr, $($key:expr => $value:expr),* $(,)?) => {
+        $logger.with_context(
+            $crate::common::logging::LogLevel::$level,
+            $category,
+            $message,
+            |ctx| {
+                $(
+                    ctx.push(($key.to_string(), format!("{}", $value)));
+                )*
+            }
+        );
+    };
+}
